/* ══════════════════════════════════════════
   images.js — Bircan Elektrik Görsel Yönetimi
   
   KULLANIM: Görseli değiştirmek için sadece
   URL'yi güncelleyin. Unsplash, kendi sunucu,
   Google Drive vb. çalışır.
   
   Format: 'https://...' veya '/images/dosya.jpg'
   ══════════════════════════════════════════ */

window.BIRCAN_IMAGES = {

  /* ── LOGO ── */
  logo: 'data:image/png;base64,',  /* örn: '/images/bircan-logo.png' */

  /* ── HERO ARKAPLAN ── */
  hero: 'data:image/jpeg;base64,',

  /* ── BÖLÜM ARKA PLAN GÖRSELLERİ ── */
  sections: {
    vizyon:    'https://images.unsplash.com/photo-1618221195710-dd6b41faaea6?auto=format&fit=crop&w=2000&q=60',
    hizmetler: 'https://images.unsplash.com/photo-1504328345606-18bbc8c9d7d1?auto=format&fit=crop&w=2000&q=60',
    teknik:    'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?auto=format&fit=crop&w=2000&q=60',
    ekip:      'https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&w=2000&q=60'
  },

  /* ── REFERANS PROJELERİ ───────────────────────────────────────
     Sıra refData[] ile birebir eşleşmelidir.
     Gerçek fotoğraf eklemek için: '/images/proje.jpg' yazın.    */
        projects: [
    // 0 — TOKİ 3. Etap — Ataşehir Altyapı (çok katlı konut inşaatı)
    'https://i.ibb.co/pj99KZgy/t-o-k-i-atasehir.jpg',
    // 1 — Tekstil Fabrikası Enerji Dengeleme (endüstriyel fabrika iç mekan)
    'https://i.ibb.co/QF95RZCM/20250923094015-1.jpg',
    // 2 — Kompanzasyon Panosu (elektrik panosu/sigorta kutusu)
    'https://i.ibb.co/TMK6kNCP/20260410-153150.jpg',
    // 3 — Araç Lifti Otomasyon (oto tamir/sanayi atölyesi)
    'https://i.ibb.co/Mk6kWjJ0/Fotoram-io-1.jpg',
    // 4 — YİBO Güvenlik Sistemleri (okul koridoru/bina)
    'https://images.unsplash.com/photo-1580582932707-520aed937b7b?auto=format&fit=crop&w=800&q=80',
    // 5 — Fen Lisesi Kütüphanesi Dekoratif Aydınlatma (modern kütüphane ışık)
    'https://i.ibb.co/XZJSn8Fq/20251128-165753.png',
    // 6 — Güneş Paneli Sistemleri (solar panel kurulum)
    'https://images.unsplash.com/photo-1509391366360-2e959784a276?auto=format&fit=crop&w=800&q=80',
    // 7 — YİBO Lojman Tesisat Revizyonu (konut elektrik/sigorta kutusu)
    'https://i.ibb.co/DgLqtxr2/20260410-154153.jpg',
    // 8 — Mağaza Aydınlatma (ticari mağaza showroom ışıklandırma)
    'https://i.ibb.co/5gMwk22S/image-Picsart-Ai-mage-Enhancer.png',
    // 9 — Diş Kliniği Aydınlatma (klinik bekleme salonu ambiyans)
    'https://i.ibb.co/LD7fwDcB/20260123-184047.jpg',
    // 10 — Yahyalı TOKİ Saha Altyapı (inşaat sahası kablo döşeme)
    'https://i.ibb.co/7N0KDCmZ/MG-20251124-WA0011.jpg',
    // 11 — Sahadan referanslar;
    'https://i.ibb.co/vvjvpr2y/1775239028022.png'
  ],

  /* ── EKİP ── */
  team: {
    cuma:  '', // örn: '/images/cuma-bircan.jpg'
    burak: ''  // örn: '/images/burak-bircan.jpg'
  }

};

/* ══════════════════════════════════════════
   UYGULAMA — DOM hazır olunca görselleri yerleştir
   ══════════════════════════════════════════ */
document.addEventListener('DOMContentLoaded', function () {
  var IMG = window.BIRCAN_IMAGES;
  var projectImageMap = {
    'toki-3-etap-atasehir-altyapi':               IMG.projects[0] || '',
    'tekstil-fabrikasi-enerji-dengeleme':          IMG.projects[1] || '',
    'kompanzasyon-panosu-optimizasyonu':           IMG.projects[2] || '',
    'ikinci-el-arac-lifti-sifirdan-otomasyon':     IMG.projects[3] || '',
    'yibo-guvenlik-ve-enerji-sistemleri':          IMG.projects[4] || '',
    'fen-lisesi-kutuphanesi-dekoratif-aydinlatma': IMG.projects[5] || '',
    'yaylalarda-gunes-paneli-sistemleri':          IMG.projects[6] || '',
    'yibo-lojman-tesisat-koruma-revizyonu':        IMG.projects[7] || '',
    'kumsmall-sivas-caddesi-magaza-cozumleri':     IMG.projects[8] || '',
    'dis-klinigi-bekleme-salonu-aydinlatmasi':     IMG.projects[9] || '',
    'yahyali-toki-saha-altyapi-vinc-beslemesi':   IMG.projects[10] || '',
    'sahadan-referanslar':                         IMG.projects[11] || ''
  };

  function slugifyProjectTitle(text) {
    return (text || '')
      .toLowerCase()
      .replace(/ı/g, 'i')
      .replace(/ğ/g, 'g')
      .replace(/ü/g, 'u')
      .replace(/ş/g, 's')
      .replace(/ö/g, 'o')
      .replace(/ç/g, 'c')
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-+|-+$/g, '');
  }

  /* ── REFERANS PROJELERİ ── */
  /* bircan.js renderRef()'i çağırdıktan sonra çalıştır */
  function applyProjectImages() {
    var cards = document.querySelectorAll('.ref-card');
    if (!cards.length) return;
    var changed = false;

    cards.forEach(function (card, i) {
      /* Kaçıncı projeyi gösterdiğini title'dan bul */
      var title = card.querySelector('.ref-title');
      if (!title) return;

      /* Görsel wrapper zaten varsa atla */
      if (card.querySelector('.ref-img-wrap')) return;

      /* Kart başlığına göre sabit görsel eşleştir */
      var imgUrl = projectImageMap[slugifyProjectTitle(title.textContent)] || '';
      if (!imgUrl) return;

      /* Kart başına görsel ekle */
      var wrap = document.createElement('div');
      wrap.className = 'ref-img-wrap img-gsap-wrap';
      wrap.style.cssText = 'width:100%;height:180px;overflow:hidden;display:block;';

      var img = document.createElement('img');
      img.src = imgUrl;
      img.alt = title.textContent;
      img.style.cssText = 'width:100%;height:100%;object-fit:cover;display:block;';
      img.loading = 'lazy';

      wrap.appendChild(img);
      card.insertBefore(wrap, card.firstChild);
      changed = true;

      /* GSAP varsa grayscale efekti uygula */
      if (typeof gsap !== 'undefined') {
        gsap.set(img, { filter: 'grayscale(100%) brightness(0.55)', scale: 1 });
        wrap.addEventListener('mouseenter', function () {
          gsap.to(img, { filter: 'grayscale(0%) brightness(0.88)', scale: 1.05, duration: 1.2, ease: 'power3.out' });
        });
        wrap.addEventListener('mouseleave', function () {
          gsap.to(img, { filter: 'grayscale(100%) brightness(0.55)', scale: 1, duration: 1.5, ease: 'power3.out' });
        });
      }
    });

    if (changed && typeof ScrollTrigger !== 'undefined') {
      requestAnimationFrame(function () {
        ScrollTrigger.refresh();
      });
    }
  }

  /* Referanslar yeniden render edildiğinde görselleri anında tekrar ekle */
  if (typeof window.renderRef === 'function') {
    var originalRenderRef = window.renderRef;
    window.renderRef = function () {
      originalRenderRef.apply(this, arguments);
      applyProjectImages();
    };
  }

  /* İlk render için gecikmesiz uygula */
  applyProjectImages();

  /* ── EKİP GÖRSELLERİ ── */
  if (IMG.team.cuma || IMG.team.burak) {
    var teamCards = document.querySelectorAll('#ekip [style*="padding:1.75rem"]');
    var keys = ['cuma', 'burak'];
    teamCards.forEach(function (card, i) {
      var key = keys[i];
      if (!key || !IMG.team[key]) return;
      if (card.querySelector('.team-img-wrap')) return;

      var wrap = document.createElement('div');
      wrap.className = 'team-img-wrap img-gsap-wrap';
      wrap.style.cssText = 'width:100%;height:220px;overflow:hidden;display:block;margin-bottom:1.5rem;';

      var img = document.createElement('img');
      img.src = IMG.team[key];
      img.alt = key === 'cuma' ? 'Cuma Bircan' : 'Burak Bircan';
      img.style.cssText = 'width:100%;height:100%;object-fit:cover;display:block;';

      wrap.appendChild(img);
      card.insertBefore(wrap, card.firstChild);

      if (typeof gsap !== 'undefined') {
        gsap.set(img, { filter: 'grayscale(100%) brightness(0.55)' });
        wrap.addEventListener('mouseenter', function () {
          gsap.to(img, { filter: 'grayscale(0%) brightness(0.85)', duration: 1.2, ease: 'power3.out' });
        });
        wrap.addEventListener('mouseleave', function () {
          gsap.to(img, { filter: 'grayscale(100%) brightness(0.55)', duration: 1.5, ease: 'power3.out' });
        });
      }
    });
  }

  /* ── LOGO ── */
  var logoImg = document.querySelector('#nav-logo-img');
  if (logoImg && IMG.logo) {
    logoImg.src = IMG.logo;
    logoImg.style.display = 'block';
  }

  /* ── BÖLÜM ARKA PLAN GÖRSELLERİ ── */
  var sectionBgMap = {
    'vizyon':    IMG.sections && IMG.sections.vizyon,
    'hizmetler': IMG.sections && IMG.sections.hizmetler,
    'teknik':    IMG.sections && IMG.sections.teknik,
    'ekip':      IMG.sections && IMG.sections.ekip
  };

  Object.keys(sectionBgMap).forEach(function(id) {
    var url = sectionBgMap[id];
    if (!url) return;
    var el = document.getElementById(id);
    if (!el) return;

    /* Section'a relative position ver */
    el.style.position = 'relative';
    el.style.overflow = 'hidden';

    /* Arka plan görsel katmanı */
    var bg = document.createElement('div');
    bg.style.cssText = [
      'position:absolute', 'inset:0', 'z-index:0',
      'background-image:url(' + url + ')',
      'background-size:cover',
      'background-position:center',
      /* Çok koyu — sadece atmosfer, okunabilirlik bozulmasın */
      'filter:brightness(0.06) saturate(0.3)',
      'pointer-events:none',
      'transition:filter 0.8s ease'
    ].join(';');
    el.insertBefore(bg, el.firstChild);

    /* Section içeriğini üste al */
    Array.from(el.children).forEach(function(child) {
      if (child !== bg) {
        child.style.position = 'relative';
        child.style.zIndex = '1';
      }
    });

    /* Scroll ile hafif parallax */
    if (typeof gsap !== 'undefined') {
      gsap.to(bg, {
        yPercent: 15,
        ease: 'none',
        scrollTrigger: {
          trigger: el,
          start: 'top bottom',
          end: 'bottom top',
          scrub: true
        }
      });
    }
  });

  /* ── HERO ARKAPLAN GÖRSELİ ── */
  if (IMG.hero) {
    var heroEl = document.querySelector('.hero');
    if (heroEl) {
      var heroBg = document.createElement('div');
      heroBg.style.cssText = [
        'position:absolute', 'inset:0', 'z-index:0',
        'background-image:url(' + IMG.hero + ')',
        'background-size:cover', 'background-position:center',
        'filter:brightness(0.26) saturate(0.55) contrast(0.96)',
        'opacity:0.78',
        'pointer-events:none'
      ].join(';');
      heroEl.insertBefore(heroBg, heroEl.firstChild);
    }
  }

});

/* ══════════════════════════════════════════
   GOOGLE MAPS / GOOGLE İŞLETMEM GÖRSELLERİ

   1. Google İşletmem'e gir (business.google.com)
   2. Sol menü → Fotoğraflar
   3. Görsele sağ tık → "Resim adresini kopyala"
   4. Kopyaladığın URL'yi yukarıdaki projects[] dizisine yapıştır

   ÖNEMLİ: Google Maps görselleri zaman zaman
   erişim kısıtlayabilir. Güvenilir yöntemler:
   • Görseli bilgisayara indir → sunucuna yükle → /images/proje.jpg
   • Cloudinary veya imgbb.com'a yükle (ücretsiz CDN)
   • Google Drive'a yükle → "Herkese açık" yap → doğrudan link al

   DRIVE LINK FORMAT:
   https://drive.google.com/file/d/DOSYA_ID/view
   → https://lh3.googleusercontent.com/d/DOSYA_ID şeklinde kullan
   ══════════════════════════════════════════ */
